        ctx.save_for_backward(A, B, bias)
        C = torch.matmul(A, B)
        if bias is not None:
            C += bias
        if relu:
            C = torch.relu(C)
        if scale is not None:
            C *= scale
        if clamp_min is not None or clamp_max is not None:
            C = torch.clamp(C, min=clamp_min, max=clamp_max)
        return C

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        A, B, bias = ctx.saved_tensors
        grad_A = torch.matmul(grad_output, B.t())
        grad_B = torch.matmul(A.t(), grad_output)
        grad_bias = None
        if bias is not None:
            grad_bias = torch.sum(grad_output, dim=0)
        return grad_A, grad_B, grad_bias, None, None, None, None

