#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void bmm_with_bias_relu_kernel(const float* A, const float* B, float* C, const float* bias, int batch_size, int m, int n, int k) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    int aBegin = by * TILE_SIZE;
    int aEnd = aBegin + m;
    int aStep = TILE_SIZE;

    int bBegin = bx * TILE_SIZE;
    int bEnd = bBegin + k;
    int bStep = TILE_SIZE;

    float cValue = 0.0f;

    for (int a = aBegin, b = bBegin; a < aEnd; a += aStep, b += bStep) {
        As[ty][tx] = (a < m && b < k) ? A[a * k + b] : 0.0f;
        Bs[ty][tx] = (b < k && ty < n) ? B[b * n + ty] : 0.0f;
        __syncthreads();

        for (int bk = 0; bk < TILE_SIZE; ++bk) {
            cValue += As[ty][bk] * Bs[bk][tx];
        }
        __syncthreads();
    }

    int c = by * TILE_SIZE + bx * TILE_SIZE + ty * n + tx;
    if (c < m * n) {
        C[c] = cValue + bias[ty];
        C[c] = C[c] > 0.0f ? C[c] : 0.0f;
    }
}

torch::Tensor bmm_with_bias_relu(torch::Tensor A, torch::Tensor B, torch::Tensor bias) {
    int batch_size = A.size(0);
    int m = A.size(1);
    int n = B.size(2);
    int k = A.size(2);

    auto C = torch::zeros({batch_size, m, n}, A.options());

    dim3 blocks((n + TILE_SIZE - 1) / TILE_SIZE, (m + TILE_SIZE - 1) / TILE_SIZE, batch_size);
    dim3 threads(TILE_SIZE, TILE_SIZE);

    bmm_with_bias_relu_kernel<<<blocks, threads>>>(A.data_ptr<float>(), B.data_ptr<float>(), C.data_ptr<float>(), bias.data_ptr<float>(), batch_size, m, n, k);

    return C;
