#include <torch/extension.h>

// Define the fused linear, bias, ReLU operation
void fused_linear_bias_relu(torch::Tensor input, torch::Tensor weight, torch::Tensor bias, torch::Tensor output) {
    int m = input.size(0);
    int n = input.size(1);
    int k = weight.size(1);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < k; ++j) {
            float sum = 0;
            for (int l = 0; l < n; ++l) {
                sum += input[i * n + l] * weight[j * n + l];
            }
            output[i * k + j] = std::max(sum + bias[j], 0.0f);
        }
    }
}
