        for (int kk = 0; kk < TILE_WIDTH; ++kk) {
            Csub += As[ty][kk] * Bs[kk][tx];
        }

        __syncthreads();
    }

    if (Row < m * TILE_WIDTH + TILE_WIDTH && Col < n) {
        C[Row * n + Col] = Csub;
    }
}

void fused_linear_bias_relu_cuda(torch::Tensor input, torch::Tensor weight, torch::Tensor bias, torch::Tensor output) {
    int m = input.size(0);
